# [doc = " Encode a [`DenseMap`] into its canonical, deterministic, injective, length-prefixed bytes"] # [doc = " (ADR-037 §2) — the OCI config blob payload. **Injectivity is the whole contract**, same as"] # [doc = " [`crate::content_address`]: every free-text field (`name`, `version`, `rel_path`, dependency"] # [doc = " `name`/`phylum`/`hash`/`version`) is length-prefixed so an embedded space/newline/colon cannot"] # [doc = " alias two distinct dense-maps onto one encoding. Fixed-vocabulary fields (`kind`) and"] # [doc = " already-charset-restricted fields (`ContentHash`, which cannot contain a newline by construction"] # [doc = " — [`ContentHash::parse`]) are written as plain lines. Sections are sorted here (`surface`,"] # [doc = " `objects` by `rel_path`, `deps` by name) regardless of input order, so two [`DenseMap`]s with the"] # [doc = " same logical content always encode identically."] # [must_use] pub fn encode_dense_map (dm : & DenseMap) -> Vec < u8 > { let mut surface = dm . surface . clone () ; surface . sort () ; let mut objects = dm . objects . clone () ; objects . sort_by (| a , b | a . rel_path . cmp (& b . rel_path)) ; let mut deps = dm . deps . clone () ; deps . sort_by (| a , b | a . name . cmp (& b . name)) ; let mut out = String :: from (DENSE_MAP_HEADER) ; out . push_str (& format ! ("spore_id:{}
" , dm . spore_id . as_str ())) ; out . push_str (& format ! ("kind:{}
" , kind_str (dm . kind))) ; out . push_str ("name:") ; push_len_field (& mut out , & dm . name) ; push_opt_field (& mut out , "version:" , dm . version . as_deref ()) ; out . push_str (& format ! ("surface {}
" , surface . len ())) ; for s in & surface { push_len_field (& mut out , s) ; } out . push_str (& format ! ("objects {}
" , objects . len ())) ; for o in & objects { out . push_str ("objpath:") ; push_len_field (& mut out , & o . rel_path) ; out . push_str (& format ! ("objhash:{}
" , o . content_hash . as_str ())) ; } out . push_str (& format ! ("deps {}
" , deps . len ())) ; for d in & deps { out . push_str ("depname:") ; push_len_field (& mut out , & d . name) ; out . push_str ("depphylum:") ; push_len_field (& mut out , & d . phylum) ; out . push_str ("dephash:") ; push_len_field (& mut out , & d . hash) ; push_opt_field (& mut out , "depversion:" , d . version . as_deref ()) ; } out . into_bytes () }

# [doc = " Spawn `oras`, mapping a missing binary to [`RemoteError::ToolMissing`] (never a silent skip) and"] # [doc = " any other spawn failure to [`RemoteError::Transport`]."] fn spawn_oras (mut cmd : Command) -> Result < std :: process :: Output , RemoteError > { cmd . output () . map_err (| e | { if e . kind () == std :: io :: ErrorKind :: NotFound { RemoteError :: ToolMissing ("the `oras` CLI is not on PATH — it is the v0 OCI wire-transport driver (ADR-037 §1); \
                 install it (https://oras.land) or publish/resolve against a local (non-`oci://`/`ghcr://`) \
                 registry path instead" . to_owned () ,) } else { RemoteError :: Transport (format ! ("failed to spawn `oras`: {e}")) } }) }
